#include <stddef.h>
#include <stdint.h>
#include "syscall.h"
#include "vfs.h"
#include "proc.h"
#ifndef EXOCORE_VERSION
#define EXOCORE_VERSION "unknown"
#endif
#define MAX_ARGC 16
#define HIST_MAX 32
#define LINE_MAX 192
static char hist[HIST_MAX][LINE_MAX]; static int hist_count=0,hist_next=0;
static long syscall3(long n,long a,long b,long c){long r;__asm__ volatile("int $0x80":"=a"(r):"a"(n),"D"(a),"S"(b),"d"(c):"memory");return r;}
static size_t slen(const char*s){size_t n=0;while(s&&s[n])n++;return n;} static int seq(const char*a,const char*b){size_t i=0;while(a[i]&&b[i]&&a[i]==b[i])i++;return a[i]==b[i];}
static int contains(const char*s,const char*n){if(!*n)return 1;for(size_t i=0;s[i];i++){size_t j=0;while(s[i+j]&&n[j]&&s[i+j]==n[j])j++;if(!n[j])return 1;}return 0;}
static void outn(const char*s,size_t n){syscall3(SYS_WRITE,(long)s,(long)n,0);} static void out(const char*s){outn(s,slen(s));} static void nl(void){out("\n");}
static void udec(unsigned long v){char b[24];int i=23;b[i]=0;if(!v)b[--i]='0';while(v){b[--i]='0'+v%10;v/=10;}out(&b[i]);}
static long num(const char*s,int*ok){long v=0;int any=0;*ok=0;while(*s>='0'&&*s<='9'){any=1;v=v*10+*s-'0';s++;}if(any&&!*s)*ok=1;return v;}
static void hex2(unsigned char v){char h[]="0123456789ABCDEF";char b[2]={h[v>>4],h[v&15]};outn(b,2);} static void hex8(unsigned long v){for(int i=28;i>=0;i-=4){char c="0123456789ABCDEF"[(v>>i)&15];outn(&c,1);}}
static void cpy(char*d,const char*s,size_t n){size_t i=0;while(i+1<n&&s&&s[i]){d[i]=s[i];i++;}d[i]=0;} static void catp(char*d,const char*s,size_t n){size_t i=slen(d),j=0;while(i+1<n&&s&&s[j])d[i++]=s[j++];d[i]=0;}
static int parse(char*l,char**av,int max){int ac=0;char*p=l;while(*p&&ac<max){while(*p==' '||*p=='\t')p++;if(!*p)break;if(*p=='"'){p++;av[ac++]=p;while(*p&&*p!='"')p++;}else{av[ac++]=p;while(*p&&*p!=' '&&*p!='\t')p++;}if(*p)*p++=0;}return ac;}
static int openr(const char*p){return (int)syscall3(SYS_VFS_OPEN,(long)p,VFS_O_RDONLY,0);} static int openw(const char*p,int f){return (int)syscall3(SYS_VFS_OPEN,(long)p,f,0);} static long rd(int fd,char*b,size_t n){return syscall3(SYS_VFS_READ,fd,(long)b,n);} static long wr(int fd,const char*b,size_t n){return syscall3(SYS_VFS_WRITE,fd,(long)b,n);} static void closefd(int fd){syscall3(SYS_VFS_CLOSE,fd,0,0);} static void need(const char*c,const char*u){out(c);out(": usage: ");out(u);nl();}
static void list(const char*p,int d){int fd=openr(p&&*p?p:".");if(fd<0){out("ls: cannot open path\n");return;}vfs_dirent_t e[8];long n;while((n=syscall3(SYS_VFS_GETDENTS,fd,(long)e,8))>0)for(long i=0;i<n;i++){if(d){out(e[i].type==VFS_TYPE_DIR?"d ":"f ");udec(e[i].size);out(" ");}out(e[i].name);nl();}closefd(fd);} 
static void catcmd(const char*p){if(!p||!*p){need("cat","cat <file>");return;}char b[256];int fd=openr(p);if(fd<0){out("cat: cannot open file\n");return;}long n;while((n=rd(fd,b,sizeof b))>0)outn(b,(size_t)n);if(n<0)out("cat: read failed\n");closefd(fd);} 
static void statcmd(const char*p){if(!p||!*p){need("stat","stat <path>");return;}vfs_stat_t st;if(syscall3(SYS_VFS_STAT,(long)p,(long)&st,0)!=0){out("stat: path not found\n");return;}out(st.type==VFS_TYPE_DIR?"directory ":"file ");out("size=");udec(st.size);out(" inode=");udec(st.inode);out(" children=");udec(st.children);nl();}
static void writecmd(char**av,int ac,int app){if(ac<3){need(av[0],app?"append <file> <text>":"write <file> <text>");return;}int fd=openw(av[1],VFS_O_CREAT|VFS_O_RDWR|(app?VFS_O_APPEND:VFS_O_TRUNC));if(fd<0){out(av[0]);out(": cannot open file\n");return;}for(int i=2;i<ac;i++){if(i>2)wr(fd," ",1);wr(fd,av[i],slen(av[i]));}wr(fd,"\n",1);closefd(fd);} 
static void cpcmd(char**av,int ac){if(ac!=3){need("cp","cp <src> <dst>");return;}int s=openr(av[1]);if(s<0){out("cp: cannot open source\n");return;}int d=openw(av[2],VFS_O_CREAT|VFS_O_RDWR|VFS_O_TRUNC);if(d<0){out("cp: cannot open destination\n");closefd(s);return;}char b[512];long n;int bad=0;while((n=rd(s,b,sizeof b))>0)if(wr(d,b,(size_t)n)!=n){bad=1;break;}if(n<0)bad=1;closefd(s);closefd(d);if(bad)out("cp: copy failed\n");}
static void headcmd(char**av,int ac){if(ac<2){need("head","head <file> [n]");return;}int ok=1,limit=10;if(ac>2)limit=(int)num(av[2],&ok);if(!ok||limit<0){out("head: invalid line count\n");return;}int fd=openr(av[1]);if(fd<0){out("head: cannot open file\n");return;}char c;int lines=0;while(lines<limit&&rd(fd,&c,1)==1){outn(&c,1);if(c=='\n')lines++;}closefd(fd);} 
static void tailcmd(char**av,int ac){if(ac<2){need("tail","tail <file> [n]");return;}int ok=1,limit=10;if(ac>2)limit=(int)num(av[2],&ok);if(!ok||limit<0){out("tail: invalid line count\n");return;}char b[4096];int fd=openr(av[1]);if(fd<0){out("tail: cannot open file\n");return;}long total=0,n;while((n=rd(fd,b+total,sizeof(b)-total))>0){total+=n;if(total==(long)sizeof(b)){char x;if(rd(fd,&x,1)>0){out("tail: file too large for shell buffer\n");closefd(fd);return;}}}closefd(fd);long pos=total;int lines=0;while(pos>0&&lines<limit){pos--;if(b[pos]=='\n'&&pos<total-1)lines++;}outn(b+pos,(size_t)(total-pos));}
static void grepcmd(char**av,int ac){if(ac!=3){need("grep","grep <pattern> <file>");return;}char b[4096];int fd=openr(av[2]);if(fd<0){out("grep: cannot open file\n");return;}long n=rd(fd,b,sizeof(b)-1);closefd(fd);if(n<0){out("grep: read failed\n");return;}if(n==(long)sizeof(b)-1)out("grep: warning: file truncated to shell buffer\n");b[n]=0;char*line=b;for(long i=0;i<=n;i++)if(b[i]=='\n'||b[i]==0){char save=b[i];b[i]=0;if(contains(line,av[1])){out(line);nl();}b[i]=save;line=b+i+1;}}
static void stringscmd(char**av,int ac){if(ac!=2){need("strings","strings <file>");return;}int fd=openr(av[1]);if(fd<0){out("strings: cannot open file\n");return;}char run[128];int len=0;char c;while(rd(fd,&c,1)==1){if(c>=32&&c<=126){if(len<127)run[len++]=c;}else{if(len>=4){run[len]=0;out(run);nl();}len=0;}}if(len>=4){run[len]=0;out(run);nl();}closefd(fd);} 
static void hexdumpcmd(char**av,int ac){if(ac<2){need("hexdump","hexdump <file> [max_bytes]");return;}int ok=1,max=256;if(ac>2)max=(int)num(av[2],&ok);if(!ok||max<0){out("hexdump: invalid max_bytes\n");return;}int fd=openr(av[1]);if(fd<0){out("hexdump: cannot open file\n");return;}unsigned char b[16];long off=0,n;while(off<max&&(n=rd(fd,(char*)b,(max-off)>16?16:(size_t)(max-off)))>0){hex8(off);out("  ");for(int i=0;i<16;i++){if(i<n)hex2(b[i]);else out("  ");out(" ");}out(" ");for(int i=0;i<n;i++){char c=(b[i]>=32&&b[i]<=126)?b[i]:'.';outn(&c,1);}nl();off+=n;}closefd(fd);} 
static void treewalk(const char*p,int depth){if(depth>8){out("...\n");return;}int fd=openr(p);if(fd<0){out("tree: cannot open ");out(p);nl();return;}vfs_dirent_t e[8];long n;while((n=syscall3(SYS_VFS_GETDENTS,fd,(long)e,8))>0)for(long i=0;i<n;i++){if(seq(e[i].name,".")||seq(e[i].name,".."))continue;for(int j=0;j<depth;j++)out("  ");out(e[i].name);nl();if(e[i].type==VFS_TYPE_DIR){char child[VFS_MAX_PATH];cpy(child,p,sizeof child);if(!seq(child,"/"))catp(child,"/",sizeof child);catp(child,e[i].name,sizeof child);treewalk(child,depth+1);}}closefd(fd);} 
static void findwalk(const char*p,const char*term,int depth){if(depth>8)return;int fd=openr(p);if(fd<0)return;vfs_dirent_t e[8];long n;while((n=syscall3(SYS_VFS_GETDENTS,fd,(long)e,8))>0)for(long i=0;i<n;i++){if(seq(e[i].name,".")||seq(e[i].name,".."))continue;char child[VFS_MAX_PATH];cpy(child,p,sizeof child);if(!seq(child,"/"))catp(child,"/",sizeof child);catp(child,e[i].name,sizeof child);if(contains(e[i].name,term)) {out(child);nl();} if(e[i].type==VFS_TYPE_DIR)findwalk(child,term,depth+1);}closefd(fd);} 
static const char* state(int s){return s==PROC_STATE_READY?"READY":s==PROC_STATE_RUNNING?"RUN":s==PROC_STATE_EXITED?"EXIT":"UNUSED";} static void pinfo(int pid){proc_info_t pi;if(syscall3(SYS_PROC_INFO,pid,(long)&pi,0)!=0){out("pinfo: process not found\n");return;}out("pid=");udec(pi.pid);out(" ppid=");udec(pi.parent_pid);out(" state=");out(state(pi.state));out(" exit=");udec(pi.exit_status);out(" name=");out(pi.name);out(" exe=");out(pi.exe_path);out(" cwd=");out(pi.cwd);nl();}
static void help(void){out("Builtins:\n  help clear echo version about exit history\nFiles:\n  pwd cd ls ll tree stat find cat touch write append truncate rm mkdir rmdir mv cp size head tail hexdump strings wc grep access\nProcesses:\n  pid ppid ps pinfo run spawn wait kill\nSystem:\n  mem dmesg uptime sleep sync banner printtest alloctest\n");}
static void banner(void){out("=== ExoCore shelld ===\n");}
static void addhist(const char*l){if(!l||!*l)return;cpy(hist[hist_next],l,LINE_MAX);hist_next=(hist_next+1)%HIST_MAX;if(hist_count<HIST_MAX)hist_count++;}
static void runline(char*line){char*av[MAX_ARGC];int ac=parse(line,av,MAX_ARGC);if(!ac)return;char*cmd=av[0];
if(seq(cmd,"help"))help();else if(seq(cmd,"clear")){for(int i=0;i<30;i++)nl();}else if(seq(cmd,"echo")){for(int i=1;i<ac;i++){if(i>1)out(" ");out(av[i]);}nl();}else if(seq(cmd,"version")){out(EXOCORE_VERSION);nl();}else if(seq(cmd,"about"))out("ExoCore Kernel shell daemon\n");else if(seq(cmd,"history")){int start=(hist_next-hist_count+HIST_MAX)%HIST_MAX;for(int i=0;i<hist_count;i++){udec(i+1);out(" ");out(hist[(start+i)%HIST_MAX]);nl();}}
else if(seq(cmd,"pwd")){char b[128];if(!syscall3(SYS_VFS_GETCWD,(long)b,sizeof b,0))out(b);else out("pwd: failed");nl();}else if(seq(cmd,"cd")){if(ac>2)need("cd","cd [dir]");else if(syscall3(SYS_VFS_CHDIR,(long)(ac>1?av[1]:"/"),0,0))out("cd: not a directory or missing\n");}else if(seq(cmd,"ls"))list(ac>1?av[1]:".",0);else if(seq(cmd,"ll"))list(ac>1?av[1]:".",1);else if(seq(cmd,"tree")){out(ac>1?av[1]:".");nl();treewalk(ac>1?av[1]:".",1);}else if(seq(cmd,"find")){if(ac<2)need("find","find <name> [start_path]");else findwalk(ac>2?av[2]:".",av[1],0);}else if(seq(cmd,"cat"))catcmd(ac>1?av[1]:0);else if(seq(cmd,"touch")){if(ac!=2)need("touch","touch <file>");else{int fd=openw(av[1],VFS_O_CREAT|VFS_O_RDWR);if(fd<0)out("touch: failed\n");else closefd(fd);}}else if(seq(cmd,"write"))writecmd(av,ac,0);else if(seq(cmd,"append"))writecmd(av,ac,1);else if(seq(cmd,"truncate")){if(ac!=2)need("truncate","truncate <file>");else{int fd=openw(av[1],VFS_O_CREAT|VFS_O_RDWR|VFS_O_TRUNC);if(fd<0)out("truncate: failed\n");else closefd(fd);}}else if(seq(cmd,"rm")){if(ac!=2)need("rm","rm <file>");else if(syscall3(SYS_VFS_UNLINK,(long)av[1],0,0))out("rm: failed; missing file or directory\n");}else if(seq(cmd,"mkdir")){if(ac!=2)need("mkdir","mkdir <dir>");else if(syscall3(SYS_VFS_MKDIR,(long)av[1],0,0))out("mkdir: failed\n");}else if(seq(cmd,"rmdir")){if(ac!=2)need("rmdir","rmdir <dir>");else if(syscall3(SYS_VFS_RMDIR,(long)av[1],0,0))out("rmdir: failed; directory may be missing, non-empty, or not a directory\n");}else if(seq(cmd,"mv")){if(ac!=3)need("mv","mv <old> <new>");else if(syscall3(SYS_VFS_RENAME,(long)av[1],(long)av[2],0))out("mv: failed\n");}else if(seq(cmd,"cp"))cpcmd(av,ac);else if(seq(cmd,"stat")||seq(cmd,"size"))statcmd(ac>1?av[1]:0);else if(seq(cmd,"head"))headcmd(av,ac);else if(seq(cmd,"tail"))tailcmd(av,ac);else if(seq(cmd,"hexdump"))hexdumpcmd(av,ac);else if(seq(cmd,"strings"))stringscmd(av,ac);else if(seq(cmd,"wc")){if(ac!=2)need("wc","wc <file>");else{vfs_stat_t st;if(syscall3(SYS_VFS_STAT,(long)av[1],(long)&st,0))out("wc: missing file\n");else{udec(st.size);nl();}}}else if(seq(cmd,"grep"))grepcmd(av,ac);else if(seq(cmd,"access")){if(ac!=2)need("access","access <path>");else out(syscall3(SYS_VFS_ACCESS,(long)av[1],0,0)==0?"exists\n":"missing\n");}
else if(seq(cmd,"pid")){udec(syscall3(SYS_GETPID,0,0,0));nl();}else if(seq(cmd,"ppid")){udec(syscall3(SYS_GETPPID,0,0,0));nl();}else if(seq(cmd,"ps")){proc_info_t p[16];long n=syscall3(SYS_PROC_LIST,(long)p,16,0);out("PID PPID STATE NAME EXE\n");for(int i=0;i<n;i++){udec(p[i].pid);out(" ");udec(p[i].parent_pid);out(" ");out(state(p[i].state));out(" ");out(p[i].name);out(" ");out(p[i].exe_path);nl();}}else if(seq(cmd,"pinfo")){int ok,pid;if(ac!=2)need("pinfo","pinfo <pid>");else{pid=(int)num(av[1],&ok);if(!ok)out("pinfo: invalid pid\n");else pinfo(pid);}}else if(seq(cmd,"wait")){int ok,pid,st=0;if(ac!=2)need("wait","wait <pid>");else{pid=(int)num(av[1],&ok);if(!ok)out("wait: invalid pid\n");else{long r=syscall3(SYS_PROC_WAIT,pid,(long)&st,0);if(r<0)out("wait: failed\n");else{out("exit status ");udec(st);nl();}}}}else if(seq(cmd,"kill")){int ok,pid;if(ac!=2)need("kill","kill <pid>");else{pid=(int)num(av[1],&ok);if(!ok)out("kill: invalid pid\n");else out(syscall3(SYS_PROC_KILL,pid,-1,0)==0?"killed\n":"kill: failed\n");}}else if(seq(cmd,"run")||seq(cmd,"spawn")){if(ac<2)need(cmd,"run <path> [args...]");else{if(ac>2)out("run: arguments are ignored by current kernel spawn ABI\n");long r=syscall3(SYS_PROC_SPAWN_EX,(long)av[1],0,0);if(r<0)out("run: spawn failed; check path and executable format\n");else{out("spawned pid ");udec(r);nl();}}}
else if(seq(cmd,"mem")){size_t free=0;if(syscall3(SYS_MEM_INFO,(long)&free,0,0)==0){out("heap_free=");udec(free);nl();}else out("mem: failed\n");}else if(seq(cmd,"dmesg")){char b[256];long off=0,n;while((n=syscall3(SYS_DMESG_READ,(long)b,sizeof b,off))>0){outn(b,(size_t)n);off+=n;}nl();}else if(seq(cmd,"uptime")){unsigned long ms=syscall3(SYS_UPTIME_MS,0,0,0);udec(ms);out(" ms (");udec(ms/1000);out(" s)\n");}else if(seq(cmd,"sleep")){int ok;if(ac!=2)need("sleep","sleep <ms>");else{long ms=num(av[1],&ok);if(!ok)out("sleep: invalid ms\n");else syscall3(SYS_SLEEP_MS,ms,0,0);}}else if(seq(cmd,"sync")){out(syscall3(SYS_SYNC,0,0,0)==0?"sync ok\n":"sync failed\n");}else if(seq(cmd,"alloctest")){void*p=(void*)syscall3(SYS_MEM_ALLOC,64,0,0);out(p?"alloctest ok\n":"alloctest failed\n");}else if(seq(cmd,"printtest"))out("printtest ok\n");else if(seq(cmd,"banner"))banner();else out("unknown command\n");}
void _start(void){banner();out("type help for commands\n");char line[LINE_MAX];for(;;){out("exo> ");int pos=0;while(pos<(int)sizeof(line)-1){char c=0;syscall3(SYS_READ,0,(long)&c,1);if(c==0)continue;if(c=='\r')c='\n';if(c=='\n'){out("\n");break;}if(c==8||c==127){if(pos){pos--;out("\b \b");}}else{line[pos++]=c;outn(&c,1);}}line[pos]=0;if(seq(line,"exit"))break;addhist(line);runline(line);}syscall3(SYS_EXIT,0,0,0);}
